// // This module subtracts A from B if A is less than B, adds A and B if A is greater than B, and performs a bitwise AND if A equals B.
module top_module(
  input [3:0] A,
  input [3:0] B,
  output reg [4:0] C
);always @(*) begin
    C = (A < B) ? (A + B) : ((A > B) ? (A - B) : (A | B));
  end

endmodule
